-- Íŕńňđîéęč WPLine (ęîăäŕ ňî â ăóčřęó çŕíĺńó)
local WP = {
    lineWidth       = 2,
    markerRadius    = 0.4,
    markerSegments  = 48,
    markerWidth     = 2,
    groundOffset    = 0.03,
    startHeight     = 0.05,
    hideDistance    = 200.0,
    showDistance    = true,
    distanceOffsetY = 22,
}

local function wpDist3(x1,y1,z1,x2,y2,z2)
    local dx,dy,dz = x2-x1,y2-y1,z2-z1
    return math.sqrt(dx*dx+dy*dy+dz*dz)
end

local function wpWorldToScreen(x,y,z)
    local a,b,c = convert3DCoordsToScreen(x,y,z)
    if type(a) == "boolean" then
        if not a or b == nil or c == nil then return nil,nil end
        return b,c
    end
    return a,b
end

local function wpInFrontOfCamera(tx,ty,tz)
    local cx,cy,cz = getActiveCameraCoordinates()
    local lx,ly,lz = getActiveCameraPointAt()
    local fx,fy,fz = lx-cx, ly-cy, lz-cz
    local vx,vy,vz = tx-cx, ty-cy, tz-cz
    return (fx*vx+fy*vy+fz*vz) > 0.0
end

local function wpOnScreen(sx,sy)
    local sw,sh = getScreenResolution()
    return sx >= 0 and sx <= sw and sy >= 0 and sy <= sh
end

local function wpGetGroundZ(x,y,z)
    local ok,gz = pcall(getGroundZFor3dCoord, x, y, z+5.0)
    if ok and type(gz) == "number" then return gz end
    return z
end

local function wpDrawCircle(cx,cy,cz)
    local segs = WP.markerSegments
    local r    = WP.markerRadius
    local firstSX, firstSY, prevSX, prevSY
    for i = 0, segs do
        local a  = (2.0 * math.pi) * (i / segs)
        local sx, sy = wpWorldToScreen(cx + math.cos(a)*r, cy + math.sin(a)*r, cz)
        if not (sx and sy) then return end
        if i == 0 then firstSX,firstSY,prevSX,prevSY = sx,sy,sx,sy
        else
            renderDrawLine(prevSX,prevSY,sx,sy, WP.markerWidth, 0xE0FFFFFF)
            prevSX,prevSY = sx,sy
        end
    end
    if firstSX then renderDrawLine(prevSX,prevSY,firstSX,firstSY, WP.markerWidth, 0xE0FFFFFF) end
end

function drawWpTracer()
    local interior
    local ok, val = pcall(getInteriorFromChar, PLAYER_PED)
    interior = ok and val or 0
    if interior ~= 0 then return end

    local px,py,pz = getCharCoordinates(PLAYER_PED)
    local gz = wpGetGroundZ(wpX, wpY, wpZ)
    local tx,ty,tz = wpX, wpY, gz + WP.groundOffset

    local d = wpDist3(px,py,pz, tx,ty,tz)
    if d > WP.hideDistance then return end
    if not wpInFrontOfCamera(tx,ty,tz) then return end

    local startSX, startSY = wpWorldToScreen(px, py, pz + WP.startHeight)
    if not (startSX and startSY) then return end

    local targetSX, targetSY = wpWorldToScreen(tx, ty, tz)
    if not (targetSX and targetSY) then return end
    if not wpOnScreen(targetSX, targetSY) then return end

    renderDrawLine(startSX, startSY, targetSX, targetSY, WP.lineWidth, 0x90FFFFFF)
    wpDrawCircle(tx, ty, tz)

    if WP.showDistance and wpFont then
        local text  = string.format("%.0f m", d)
        local halfW = math.floor((#text * 6) / 2)
        renderFontDrawText(wpFont, text, targetSX - halfW, targetSY - WP.distanceOffsetY, 0xFFFFFFFF)
    end
end

