function checkUpdates()
    if config.customization.disableautoupdate then return end

    local ok, response = pcall(requests.get, updates_url)
    if not ok or response.status_code ~= 200 then
        sampfuncsLog("[u] Íĺ óäŕëîńü ďđîâĺđčňü îáíîâëĺíč˙!")
        return
    end

    resp = decodeJson(response.text)
    if not resp then
        sampfuncsLog("[u] Îřčáęŕ ďŕđńčíăŕ JSON!")
        return
    end
    if tonumber(resp.info["version_n"]) > version_n then
        oldVersion = true
        msg("Ĺńňü îáíîâëĺíčĺ! Âĺđńč˙: " .. resp.info["version"], "good")
        msg("×ňî áű îáíîâčňü, îňęđîéňĺ Íŕńňđîéęč.", "good")
    end
end

function checkPermissions()
    local ok, response = pcall(requests.get, permissions_url)

    if not ok or response.status_code ~= 200 then
        sampfuncsLog("[p] Íĺ óäŕëîńü çŕăđóçčňü ńďčńîę đŕçđĺřĺíčé!")
        return false
    end

    local data = decodeJson(response.text)
    if not data then
        sampfuncsLog("[p] Îřčáęŕ ďŕđńčíăŕ JSON!")
        return false
    end

    serverPermissions = data
    return true
end

function msg(mtext, tag)
    if config.messages.chat then 
        if tag == "good" then 
            sampAddChatMessage(gtag ..""..mtext.."", -1)
        elseif tag == "bad" then
            sampAddChatMessage(btag ..""..mtext.."", -1)
        else
            sampAddChatMessage(mtext, -1)
        end
    elseif config.messages.console then 
        if tag == "good" then 
            sampfuncsLog(gtag .. ""..mtext.."")
        elseif tag == "bad" then
            sampfuncsLog(btag .. ""..mtext.."")
        else
            sampfuncsLog(mtext)
        end
    elseif config.messages.silent then
        return false
    end
end

