		raknetEmulRpcReceiveBitStream(94, bs)
		raknetDeleteBitStream(bs)
        msg("Âđĺě˙ čçěĺíĺíî íŕ: "..goodcolor..""..hour.."", "bad")
		return nil
	end
	msg("Čńďîëüçóéňĺ: "..goodcolor.."/"..config.additional.stc.."{ffffff} [0 - 23]", "bad")
end

