function getSelfName()
    result, id = sampGetPlayerIdByCharHandle(PLAYER_PED)
    if result then
        sampSendChat('/cl '..id)
        name = sampGetPlayerNickname(id)
    else
        name = "Unavailable"
    end
    return name
end

function parseServer()
    local raw = sampGetCurrentServerName()
    local city = string.match(raw, '|%s*([^|]+)')
    if city then city = city:match('^(.-)%s*$') end --ńčńč ěŕńčńč
    local serverName = city and city or raw

    local perms = serverPermissions[serverName]
    if perms then
        for key, value in pairs(perms) do
            permissions[key] = value
        end
    else
        for key in pairs(permissions) do
            permissions[key] = false
        end
    end

    return serverName
end

function setFogDistance(arg)
    if not prostoahyet then  
        memory.write(5499541, 12044272, 4, false)
        memory.write(8381985, 13213544, 4, false)
        prostoahyet = true
    end
    local dist = arg:match("(%d+)")
    dist = tonumber(dist)
    if type(dist) ~= 'number' or dist > 3600 or dist < 0 then
        msg('Čńďîëüçóéňĺ: '..goodcolor..'/'..config.additional.fdc..' [0-3600]', "bad")
    else
        config.additional.dist = dist
        if not isLauncherActive then
            memory.setfloat(12044272, config.additional.dist, false)
            inicfg.save(config, "project_fraktura")
            msg('Óńňŕíîâëĺíŕ äŕëüíîńňü ďđîđčńîâęč: '..badcolor..''..config.additional.dist, "good")
        end
    end
end

function drawAvatar(dl, cx, cy, radius, nickname)
    dl:AddCircleFilled(imgui.ImVec2(cx, cy), radius, 0xFF2A2A2A, 32)
    dl:AddCircle(imgui.ImVec2(cx, cy), radius, 0xFF404040, 32, 1.5)
    local letter = string.upper(string.sub(nickname, 1, 1))
    dl:AddText(
        imgui.ImVec2(cx - 4.0, cy - 6.5),
        0xFF4D444A,
        letter
    )
end

function switchButton(label, config_table, config_key)
    imgui.SetCursorPosX(5)
    if ia.ToggleButton(u8(label), imgui.new.bool(config_table[config_key])) then
        config_table[config_key] = not config_table[config_key]
    end
end

function tabButton(label, id, width)
    local is_active = (active_tab == id)
    imgui.SetCursorPosX(3)

    if is_active then
        imgui.PushStyleColor(imgui.Col.Button,       imgui.ImVec4(0.20, 0.10, 0.10, 1.00))
        imgui.PushStyleColor(imgui.Col.ButtonHovered,imgui.ImVec4(0.30, 0.10, 0.10, 1.00))
    else
        imgui.PushStyleColor(imgui.Col.Button,       imgui.ImVec4(0.05, 0.05, 0.05, 0.00))
        imgui.PushStyleColor(imgui.Col.ButtonHovered,imgui.ImVec4(0.30, 0.10, 0.10, 1.00))
    end
    imgui.PushStyleColor(imgui.Col.ButtonActive, imgui.ImVec4(0.40, 0.10, 0.10, 1.00))

    if ia.MaterialButton(label, imgui.ImVec2(width, 38)) then
        active_tab = id
    end

    imgui.PopStyleColor(3)
end

