function tickCarDoors()
    if not (isCharInAnyCar(PLAYER_PED) and not isCharOnAnyBike(PLAYER_PED)
        and not isCharInAnyHeli(PLAYER_PED) and not isCharInAnyTrain(PLAYER_PED)
        and not isCharInAnyBoat(PLAYER_PED)) then return end

    local veh = storeCarCharIsInNoSave(PLAYER_PED)
    if checkCarParts(getCarModel(veh)) then
        if config.additional.popcardoors then
            popCarDoor(veh, 2) popCarDoor(veh, 3)
        else
            fixCarDoor(veh, 2) fixCarDoor(veh, 3)
        end
    end
end

function getFirstKey(keyJson) --÷ĺńňíîĺ ęŕęîĺ-ňî ďîńňíîĺ äĺđüěî ęîňîđîĺ â đĺŕëüíűő óńëîâč˙ő íĺ ńđŕáîňŕĺň, íî ěŕëî ëč âäđóă áë˙ ęňî-ňî çŕóěíôűé â ęîíôčă çŕéä¸ň č őóéíč íŕńđĺň. ňîëüęî â ęîíôčăĺ {} íĺ ńňŕâüňĺ, ńěĺříî áóäĺň, ďîńěĺ¸ěń˙
    local key = decodeJson(keyJson)
    local vk = type(key) == 'table' and key[1] or key
    return (vk and vk > 0) and vk or nil
end

function isPlayerActive()
    return not sampIsCursorActive()
        and isPlayerPlaying(playerHandle)
        and not sampIsChatInputActive()
        and not sampIsDialogActive()
        and not isPauseMenuActive()
end

function tickQuickmap()
    if not config.additional.quickmap then return end
    local vk = getFirstKey(config.additional.quickmapkey)
    if not vk or not isPlayerActive() or not isKeyDown(vk) then return end

    if not isLauncherActive then
        local menuPtr = 0x00BA6748
        writeMemory(menuPtr + 0x33,  1, 1, false)
        wait(0)
        writeMemory(menuPtr + 0x15C, 1, 1, false)
        writeMemory(menuPtr + 0x15D, 1, 5, false)
        writeMemory(menuPtr + 0x64,  4, representFloatAsInt(300.0), false)
        while isKeyDown(vk) do wait(50) end
        writeMemory(menuPtr + 0x32,  1, 1, false)
    else
        return
    end
end

function tickFastmap()
    if not config.additional.fastmap then map_render = false return end
    local vk = getFirstKey(config.additional.fastmapkey)
    map_render = vk and isPlayerActive() and isKeyDown(vk) or false
end

function tickServerTime()
    if not config.additional.servertime then return end
    local date_table = os.date("*t", getTime)
    local ms         = tonumber(string.sub(tostring(math.ceil(socket.gettime() * 1000)), -3))
    local renderTime = os.date("%H:%M:%S", getTime)
    local renderSecondsTime = string.format("%02d:%02d:%02d{%s}:%03d",
        date_table.hour, date_table.min, date_table.sec, config.additional.timeColor, ms)

    local text = config.additional.showseconds and renderSecondsTime or renderTime

    if changePos then
        showCursor(true)
        local cX, cY = getCursorPos()
        renderFontDrawText(renderTimeFont, text, cX, cY, 0xFFFFFFFF, false)
        if isKeyJustPressed(vkeys.VK_LBUTTON) then
            config.additional.timeX, config.additional.timeY = cX, cY
            changePos = false
            msg("Đŕńďîëîćĺíčĺ âđĺěĺíč ńîőđŕíĺíî", "good")
            showCursor(false)
        end
    else
        renderFontDrawText(renderTimeFont, text, config.additional.timeX, config.additional.timeY,
            tonumber("0xFF" .. config.additional.timeColor), false)
    end
end

function tickAnotherTime()
    if not config.additional.anothertime then
        if sampTextdrawIsExists(223) then sampTextdrawDelete(223) end
        return
    end
    local date_table = os.date("*t", getTime)
    local ms         = tonumber(string.sub(tostring(math.ceil(socket.gettime() * 1000)), -3))
    local text       = config.additional.showseconds
        and string.format("%02d:%02d:%02d:%03d", date_table.hour, date_table.min, date_table.sec, ms)
        or os.date("%H:%M:%S", getTime)

    sampTextdrawCreate(223, text, config.additional.timeServerPosX, config.additional.timeServerPosY)
    sampTextdrawSetLetterSizeAndColor(223, config.additional.servertimeSizeX, config.additional.servertimeSizeY, "0xFF" .. config.additional.servertimeColor)
    sampTextdrawSetOutlineColor(223, 0.5, 0xFF000000)
    sampTextdrawSetAlign(223, 1)
    sampTextdrawSetStyle(223, config.additional.servertimeStyle)
end

function tickCaptcha()
    local result, button, _, input = sampHasDialogRespond(trainingDlgId)
    if not result then return end
    time2 = string.format("%.3f", os.clock() - captime)
    if button == 255 then
        button, input = trButt, trInput -- îň ńëîâŕ ćîďŕ ÎŇ ŃËÎÂŔ ĆÎĎŔ ÁËßÄÜ
    end

    if button == 1 then
        if input == captcha then
            config.captcha.vcode = config.captcha.vcode + 1
            if config.main.newtimer then
                printStyledString('~g~' .. time2 .. ' sec!', 1000, 7)
            else
                msg(string.format('{ffffff}Âĺđíűé ęîä! [%.3f]', time2), "good")
            end
            if os.clock() - captime < config.captcha.record or config.captcha.record == 0 then
                config.captcha.record = floorStep(os.clock() - captime, 0.001)
            end
        else
            config.captcha.ncode = config.captcha.ncode + 1
            if config.main.newtimer then
                printStyledString('~r~' .. time2 .. ' sec!', 1000, 7)
            else
                msg(string.format('{ffffff}Íĺâĺđíűé ęîä! [%.3f] (' .. captcha .. '|' .. input .. ')', time2), "bad")
            end
        end
    end

    trButt, trInput = 0, ''
    removeTextdraws()
end

function show_arz_notify(type, title, text, time)
    local function escape_js(s)
        return s:gsub("\\", "\\\\"):gsub('"', '\\"')
    end
    local safe_type = escape_js(type)
    local safe_title = escape_js(title)
    local safe_text = escape_js(text)
    local safe_time = tostring(time)
    local str = ('window.executeEvent("event.notify.initialize", "[\\"%s\\", \\"%s\\", \\"%s\\", \\"%s\\"]");'):format(safe_type, safe_title, safe_text, safe_time)
    visualCEF(str, true)
end
function visualCEF(str, is_encoded)
    local bs = raknetNewBitStream()
    raknetBitStreamWriteInt8(bs, 17)
    raknetBitStreamWriteInt32(bs, 0)
    raknetBitStreamWriteInt16(bs, #str)
    raknetBitStreamWriteInt8(bs, is_encoded and 1 or 0)
    if is_encoded then
        raknetBitStreamEncodeString(bs, str)
    else
        raknetBitStreamWriteString(bs, str)
    end
    raknetEmulPacketReceiveBitStream(220, bs)
    raknetDeleteBitStream(bs)
end

function imgui.Link(link, text)
    text = text or link
    local tSize = imgui.CalcTextSize(text)
    local p = imgui.GetCursorScreenPos()
    local DL = imgui.GetWindowDrawList()
    local col = { 0xFFFF7700, 0xFFFF9900 }
    if imgui.InvisibleButton("##" .. link, tSize) then os.execute("explorer " .. link) end
    local color = imgui.IsItemHovered() and col[1] or col[2]
    DL:AddText(p, color, text)
    DL:AddLine(imgui.ImVec2(p.x, p.y + tSize.y), imgui.ImVec2(p.x + tSize.x, p.y + tSize.y), color)
end

