function main()
    while not isSampAvailable() do wait(0) end

    checkUpdates()
    checkPermissions()
    initResources()
    initHotkeys()

    sampRegisterChatCommand('fraktura', function() 
        nickname    = getSelfName()
        server_city = parseServer()
        date_str    = os.date('%a') .. ', ' .. os.date('%d') .. ' ' .. os.date('%B')
        renderWindow[0] = not renderWindow[0]
    end)

    if thisScript().filename ~= 'Fraktura.lua' then
        os.rename(getGameDirectory() .. "/moonloader/" .. thisScript().filename,
                  getGameDirectory() .. "/moonloader/Fraktura.lua")
    end
    msg('Çŕăđóćĺí! Ŕęňčâŕöč˙: ' .. badcolor .. 'F2 {ffffff}čëč ' ..  badcolor ..'/fraktura', "bad")

    addEventHandler('onWindowMessage', function(var_msg, wparam, lparam)
        if var_msg == wm.WM_KEYDOWN or var_msg == wm.WM_SYSKEYDOWN then
            if wparam == vkeys.VK_F2 then
                nickname    = getSelfName()
                server_city = parseServer()
                date_str    = os.date('%a') .. ', ' .. os.date('%d') .. ' ' .. os.date('%B')
                renderWindow[0] = not renderWindow[0]
            end
        end
        if var_msg == 0x001C and wparam == 1 then
            hotkey.ActiveKeys = {}
        end
        --if var_msg == 641 or var_msg == 642 or lparam == -1073741809 then hotkey.ActiveKeys = {} end -- îäčí đŕç ęčňŕéöŕ âűĺáŕëč ňŕę ĺăî č íŕçâŕëč, Őó˙î
        if var_msg == 0x100 or var_msg == 0x101 then
            if wparam == vkeys.VK_ESCAPE and renderWindow[0] and not isPauseMenuActive() then
                consumeWindowMessage(true, false)
                renderWindow[0] = false
            end
            if config.additional.antibattlepass and wparam == vkeys.VK_B then
                consumeWindowMessage(true, false)
            end
            if config.additional.antiwbook and wparam == vkeys.VK_M then
                consumeWindowMessage(true, false)
            end
        end
    end)

    while true do
        wait(0)
        getTime = os.time() + servernoe

        if update_state then
            downloadUrlToFile(script_url, thisScript().path, function(id, status, err)
                if status == dlstatus.STATUS_ENDDOWNLOADDATA then
                    msg("Ńęđčďň óńďĺříî îáíîâëĺí!", "good")
                    thisScript():reload()
                end
            end)
            break
        end

        tickCarDoors()
        tickQuickmap()
        tickFastmap()
        tickServerTime()
        tickAnotherTime()
        tickCaptcha()

        if config.additional.wpline and hasWp then drawWpTracer() end
        if config.additional.fastmap then renderMap() end
    end
end

function ev.onPassengerSync(player_id, passengersyncdata)
    local nick = sampGetPlayerNickname(player_id)
    if config.additional.carejector and ((os.clock() - lasttry) > (interval/1000)) then
        if player_id ~= select(2,sampGetPlayerIdByCharHandle(PLAYER_HANDLE)) then
            lasttry = os.clock()
            sampSendChat(("/eject %s"):format(player_id))
        end
    end
end

function ev.onShowTextDraw(textdrawId, data)
	if config.main.kapcheb then
		if data.boxColor == -2139062144 and data.backgroundColor == -16777216 and data.letterColor == -6054539 then
			kapchebX = data.position.x
			kapchebY = data.position.y
			for kapchebId = 2000, 2400 do
				if sampTextdrawIsExists(kapchebId) then
					posX, posY = sampTextdrawGetPos(kapchebId)
					if posX < 450 and posY < 170 then
						posX = posX - kapchebX + config.main.kapchebX
						posY = posY - kapchebY + config.main.kapchebY
						letSizeX, letSizeY, color1 = sampTextdrawGetLetterSizeAndColor(kapchebId)
						box, color2, sizeX, sizeY = sampTextdrawGetBoxEnabledColorAndSize(kapchebId)
						if tonumber(box) == tonumber(1) and tonumber(color1) == tonumber(4292993505) and tonumber(color2) == tonumber(4279903282) then
							sizeX = sizeX - kapchebX + config.main.kapchebX + 1
							sampTextdrawSetBoxColorAndSize(kapchebId, box, color2, sizeX, sizeY)
						end
						sampTextdrawSetPos(kapchebId, posX, posY)
					end
				end
			end
			data.position.x,data.position.y = config.main.kapchebX, config.main.kapchebY
			return {textdrawId, data}
		end
	end
end

function ev.onShowDialog(id, style, title, b1, b2, text)
    if title:find("Îňęóäŕ âű î íŕń óçíŕëč") then
        show_arz_notify('info','Číôîđěŕöč˙','Ďđč đĺăčńňđŕöčč íŕ íčę Nysson_Inmayhearti ňű ďîëó÷čřü 50ĘĘ íŕ 6 óđîâíĺ!', 5000)
    end 
    if title:find("Ââĺäčňĺ íčę ďđčăëŕńčâřĺăî") then
        show_arz_notify('info','Číôîđěŕöč˙','Çŕ ďîëó÷ĺíčĺě îňďčńűâŕňü ńţäŕ: @prokachkamirage', 5000)
    end
    if title:find("Ďđîâĺđęŕ íŕ đîáîňŕ") then
        did = id
        start = os.clock()
    end
    if string.match(text, "Ňĺęóůĺĺ âđĺě˙") then -- by valerii kalashnikov
		chislo, mesyac, god = string.match(text, "Ńĺăîäí˙ří˙˙ äŕňŕ: 	{2EA42E}(%d+):(%d+):(%d+)")
		chas, minuti, sekundi = string.match(text, "Ňĺęóůĺĺ âđĺě˙: 	{345690}(%d+):(%d+):(%d+)")
		datetime = {year = god,month = mesyac,day = chislo,hour = chas,min = minuti,sec = sekundi}
		servernoe = tostring(os.time(datetime)) - os.time()
	end
end

function ev.onSendDialogResponse(id, but, lis, input)
    if id == trainingDlgId then
        trButt = but
        trInput = input
    end
    curDlgInput = input
    if id == did then
        time = os.clock() - start
        time1 = string.format("%.3f", time)
        if config.main.timer and time ~= nil then
            msg('You entered captcha: '.. goodcolor ..'['..input..']{FFFFFF}, time: '.. goodcolor ..'['..time1..']{FFFFFF}', "good")
        end
        if config.main.newtimer and time ~= nil then
            printStyledString('~y~'..time1..' sec!', 3000, 7)
        end
    end
end

function ev.onSendCommand(str)
    local cmd, args = str:match('^/(%S+)%s*(.*)')
    if not cmd then return end
    cmd = cmd:lower()

    if config.additional.fd and not isLauncherActive then
        if cmd == config.additional.fdc:lower() then
            setFogDistance(args)
            return false
        end
    end

    if config.additional.settime then
        if cmd == config.additional.stc:lower() then
            setWorldTime(args)
            return false
        end
        if cmd == config.additional.swc:lower() then
            setWorldWeather(args)
            return false
        end
    end
end

function ev.onSendClientJoin(Ver, mod, nick, response, authKey, clientver, unk)
	if clientver == 'Arizona PC' then isLauncherActive = true end
end

function ev.onServerMessage(color, text)
    if text:find('{90EE90}Ďîçäđŕâë˙ĺě! Ňĺďĺđü ýňîň ňđŕíńďîđň ďđčíŕäëĺćčň âŕě!') then
      config.captcha.vcode = config.captcha.vcode + 1
      if time < config.captcha.record or config.captcha.record == 0 then
          config.captcha.record = floorStep(time, 0.001)
      end
      if config.main.textlovlya then
          if config.main.texttime and config.main.textcap then sampSendChat(string.format('%s [%.3f] ['..curDlgInput..']', config.main.text, time))
              elseif config.main.texttime then sampSendChat(string.format('%s [%.3f]', config.main.text, time))
              elseif config.main.textcap then sampSendChat(string.format('%s ['..curDlgInput..']', config.main.text))
          else sampSendChat((config.main.text)) end
      end
      if config.customization.recolor and config.main.jt and time ~= nil then 
        sampAddChatMessage(string.format(goodcolor ..'Ďîçäđŕâë˙ĺě! Ňĺďĺđü ýňîň ňđŕíńďîđň ďđčíŕäëĺćčň âŕě! [%.3f]', time), -1)
        return false
    elseif config.main.jt and time ~= nil then 
        sampAddChatMessage(string.format('{90EE90}Ďîçäđŕâë˙ĺě! Ňĺďĺđü ýňîň ňđŕíńďîđň ďđčíŕäëĺćčň âŕě! [%.3f]', time), -1)
