function floorStep(num, step)
    return num - num % step
end

function showCaptcha()
    removeTextdraws()
    math.randomseed(os.time() + math.floor(os.clock() * 1000000))
    for i = 1, 20 do math.random() end

    local r = math.random()^0.4
    if math.random(0, 1) == 1 then r = 1 - r end
    local scale = 0.93 + r * (1.06 - 0.94)

    t = t + 1
    sampTextdrawCreate(t, "LD_SPAC:white", 240, 116)
    sampTextdrawSetLetterSizeAndColor(t, 0, 7.3 * scale, 0x80808080)
    sampTextdrawSetBoxColorAndSize(t, 1, 0xFF1A2432, 404, 0.000000)

    t = t + 1
    sampTextdrawCreate(t, "LD_SPAC:white", 242, 119)
    sampTextdrawSetLetterSizeAndColor(t, 0, 6.5 * scale, 0x80808080)
    sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, 400, 0.000000)

    nextPos = math.random() * (31 - 30) - 30.5
    for i = 1, 4 do
        a = math.random(0, 9)
        table.insert(captchaTable, a)
        captcha = captcha..a
    end

    local lastDigit
    if captchaZero or math.random() < zeroChance then
        lastDigit = 0
    else
        lastDigit = math.random(0, 9)
    end
    table.insert(captchaTable, lastDigit)
    captcha = captcha..lastDigit

    for i = 0, 4 do
        nextPos = nextPos + math.random() * (31 - 30) + 29.5
        t = t + 1
        sampTextdrawCreate(t, "usebox", 259 + nextPos, 124)
        sampTextdrawSetLetterSizeAndColor(t, 0, (math.random() * (5.3 - 5) + 5) * scale, 0x80808080)
        sampTextdrawSetBoxColorAndSize(t, 1, 0xFF1A2432, 30, math.random() * (26.5 - 25) + 25)
        sampTextdrawSetAlign(t, 2)
        GenerateTextDraw(captchaTable[i + 1], 259 + nextPos, 124, 3 + i * 2, scale)
    end
    captchaTable = {}
    sampShowDialog(trainingDlgId, '{F89168}Ňđĺíčđîâęŕ ęŕď÷č', '{FFFFFF}Ââĺäčňĺ {C6FB4A}5{FFFFFF} ńčěâîëîâ, ęîňîđűĺ\nďî˙âčëčńü ó Âŕń {C6FB4A}íŕ{FFFFFF} ýęđŕíĺ.', 'Ďđčí˙ňü', 'Îňěĺíŕ', 1)
    captime = os.clock()
end

function removeTextdraws()
  if t > 0 then
    for i = 1, t do sampTextdrawDelete(i) end
    t = 0
    captcha = ''
    captime = nil
  end
end

function GenerateTextDraw(id, PosX, PosY, _, scale)
    scale = scale or 1.0

    if id == 0 then
        t = t + 1
        sampTextdrawCreate(t, "LD_SPAC:white", PosX - 5, PosY + 5)
        sampTextdrawSetLetterSizeAndColor(t, 0, (math.random()*(4-3)+3)*scale, 0x80808080)
        sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX+8, 0.000000)

    elseif id == 1 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then offsetX=2; offsetBX=17 else offsetX=-3; offsetBX=-17 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX-offsetX, PosY)
            sampTextdrawSetLetterSizeAndColor(t, 0, 5.7*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-offsetBX, 0.000000)
        end

    elseif id == 2 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then offsetX=-8; offsetY=8; offsetBX=16
            else offsetX=8; offsetY=28; offsetBX=-15 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX-offsetX, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, 0.85*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-offsetBX, 0.000000)
        end

    elseif id == 3 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then size=1.1; offsetY=6 else size=1.3; offsetY=25 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX+10, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, size*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-16.5, 0.000000)
        end

    elseif id == 4 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then size=1.6; offsetX=-10; offsetY=0; offsetBX=7
            else size=2.75; offsetX=-10; offsetY=25; offsetBX=16 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX-offsetX, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, size*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-offsetBX, 0.000000)
        end

    elseif id == 5 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then size=0.8; offsetX=6; offsetY=7; offsetBX=-15
            else size=1.2; offsetX=-10; offsetY=26; offsetBX=16 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX-offsetX, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, size*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-offsetBX, 0.000000)
        end

    elseif id == 6 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then size=1; offsetX=7.5; offsetY=7; offsetBX=-15
            else size=1.1; offsetX=-10; offsetY=math.random()*(29-27)+27; offsetBX=10 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX-offsetX, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, size*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-offsetBX, 0.000000)
        end

    elseif id == 7 then
        t = t + 1
        sampTextdrawCreate(t, "LD_SPAC:white", PosX-14, PosY+6)
        sampTextdrawSetLetterSizeAndColor(t, 0, 5.1*scale, 0x80808080)
        sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX+7, 0.000000)

    elseif id == 8 then
        local sizefor8 = math.random()*(9-8)+8
        for i = 0, 1 do
            t = t + 1
            if i == 0 then size=1.275; offsetY=8 else size=1.2; offsetY=28 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX+sizefor8, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, size*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-6, 0.000000)
        end

    elseif id == 9 then
        for i = 0, 1 do
            t = t + 1
            if i == 0 then size=1.25; offsetY=7; offsetBX=7
            else size=1.275; offsetY=26; offsetBX=16 end
            sampTextdrawCreate(t, "LD_SPAC:white", PosX+7, PosY+offsetY)
            sampTextdrawSetLetterSizeAndColor(t, 0, size*scale, 0x80808080)
            sampTextdrawSetBoxColorAndSize(t, 1, 0xFF759DA3, PosX-offsetBX, 0.000000)
        end
    end
end

